mapper.select:
SELECT *
FROM ds_refund
WHERE status = #{status}
ORDER BY update_time ASC, id ASC
LIMIT #{limit}

SELECT r.*, p.customer_no as customerNo
FROM ds_refund r
LEFT JOIN ds_payment_order p ON r.order_no = p.order_no


        AND r.refund_no = #{refundNo}


        AND r.order_no = #{orderNo}


        AND r.status = #{status}


        AND r.refund_policy = #{refundPolicy}


        AND r.request_source = #{requestSource}


        AND r.applicant_id = #{applicantId}


        AND r.channel_status = #{channelStatus}


ORDER BY r.create_time DESC
